/**
 * Mock data for the Operations · Receipts sub-page.
 *
 * Each receipt has cost components [base, freight, duty, handling]
 * (USD; negative = supplier credit). Classification routes the receipt:
 *   - inventory  → folds into per-unit landed cost
 *   - delivery   → attaches to a PO's freight
 *   - expense    → operating cost, routed to Finance
 */

export type RcpClass = "inventory" | "delivery" | "expense";
export type RcpStatus = "pending" | "processing" | "approved";

export interface ReceiptRaw {
  supplier: string;
  date: string;
  when: string;
  cls: RcpClass;
  status: RcpStatus;
  po: string | null;
  product: string | null;
  units: number;
  /** [base, freight, duty, handling] in USD */
  comps: [number, number, number, number];
  vision: boolean;
  deliveryNote?: boolean;
  expenseNote?: string;
}

export interface Receipt extends ReceiptRaw {
  idx: number;
  total: number;
  perUnit?: number;
  statusSort: number;
  clsSort: number;
}

export const COMP_LABEL = ["Base", "Freight", "Duty", "Handling"] as const;
