const STATUS_SORT: Record<RcpStatus, number> = { pending: 0, processing: 1, approved: 2 };
const CLASS_SORT: Record<RcpClass, number> = { inventory: 0, delivery: 1, expense: 2 };

export const RECEIPTS: Receipt[] = RAW.map((r, i) => {
  const total = r.comps.reduce((a, b) => a + b, 0);
  const perUnit = r.product && r.units > 0 ? total / r.units : undefined;
  return {
    ...r,
    idx: i,
    total,
    perUnit,
    statusSort: STATUS_SORT[r.status],
    clsSort: CLASS_SORT[r.cls],
  };
});

export type ActionKind = "review" | "match" | "approve" | "view";

export const ACTION_LABEL_LEDGER: Record<ActionKind, string> = {
  review: "Review",
  match: "Match",
  approve: "Approve",
  view: "View",
};

export const ACTION_LABEL_PANEL: Record<ActionKind, string> = {
  review: "Review & classify → Bridge",
  match: "Match to PO → Bridge",
  approve: "Approve & update costs → Bridge",
  view: "View in Bridge",
};

export function actionForReceipt(r: Receipt): { label: string; kind: ActionKind } {
  if (r.status === "pending") {
    if (r.cls === "inventory" && !r.po) return { label: ACTION_LABEL_LEDGER.match, kind: "match" };
    return { label: ACTION_LABEL_LEDGER.review, kind: "review" };
  }
  if (r.status === "processing") return { label: ACTION_LABEL_LEDGER.approve, kind: "approve" };
  return { label: ACTION_LABEL_LEDGER.view, kind: "view" };
}

