"use client";

/* ════════════════════════════════════════════════════════════════════════
   AIStrip — the canonical Magellan AI bar.

   Per OVERVIEW-UNIFICATION.md: this is the SITE-WIDE STANDARD. Every room
   (Finance, Growth, Customers, Operations, and any future room) uses this
   exact component — rooms only pass content + accent color per card.
   Never override the strip's dimensions, background, or card min-height
   in a room CSS file.

   Styles live in src/app/globals.css under `.ai-strip` (unscoped) so this
   component is consumable from any room without conflict. The card
   min-height: 218px is load-bearing — it makes the hero start at the same
   Y on every room (the fix for layout-jump-on-route-change).
   ════════════════════════════════════════════════════════════════════════ */

import type React from "react";
import { useBridge, type BridgeDept, type BridgePage } from "@/features/bridge/hooks/use-bridge";

export interface AICard {
  tag: string;
  title: string;
  body: string;
  /** CSS color string for the left border + tag color. Use a token like
   *  `var(--d-ops)` or a hex. Drives only the per-card accent — never the
   *  strip's background (which is navy on every room). */
  accent: string;
  /** Optional Bridge page this card's "Bridge →" button should open.
   *  When set, the strip wires the button to openBridge() directly so
   *  pages don't need to build their own onBridge handler. */
  bridgePage?: BridgePage;
  /** Optional dept override for the bridge target (defaults to the page's). */
  bridgeDept?: BridgeDept;
}

export interface AIStripMeta {
  confidence?: string;
  sources?: string;
  syncedAgo?: string;
}

export interface AIStripProps {
  /** Shown in the head, e.g. "Operations AI · Overview" */
  label: string;
  meta?: AIStripMeta;
  cards: AICard[];
  onBridge?: (cardIndex: number) => void;
  onGotIt?: (cardIndex: number) => void;
}

export function AIStrip({ label, meta, cards, onBridge, onGotIt }: AIStripProps) {
  const { openBridge } = useBridge();
  return (
    <section className="ai-strip">
      <div className="ai-strip-head">
        <div className="ai-strip-label">
          <div className="m-mark">M</div>
          {label}
        </div>
        <div className="ai-strip-meta">
          {meta?.confidence && (
            <span>
              <span className="dot" />
              {meta.confidence}
            </span>
          )}
          {meta?.sources && <span>{meta.sources}</span>}
          {meta?.syncedAgo && <span>{meta.syncedAgo}</span>}
        </div>
      </div>
      <div className="ai-strip-cards">
        {cards.map((card, i) => (
          <div
            key={i}
            className="ai-card"
            style={{ ["--accent" as string]: card.accent } as React.CSSProperties}
          >
            <div className="ai-card-tag">{card.tag}</div>
            <div className="ai-card-title">{card.title}</div>
            <div className="ai-card-body">{card.body}</div>
            <div className="ai-card-actions">
              <button className="btn-ai-got" onClick={() => onGotIt?.(i)}>
                Got it
              </button>
              <button
                className="btn-ai-bridge"
                onClick={() => {
                  if (card.bridgePage) openBridge(card.bridgeDept, card.bridgePage);
                  onBridge?.(i);
                }}
              >
                Bridge →
              </button>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
