"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  RECEIPTS,
  COMP_LABEL,
  COMP_COLOR,
  CLASS_LABEL,
  actionForReceipt,
  ACTION_LABEL_PANEL,
  receiptsAI,
  type Receipt,
  type RcpStatus,
  type RcpClass,
} from "@/features/ops/api/ops-receipts-data";
import "./receipts.css";

const fmtUSD = (v: number) => `$${Math.round(Math.abs(v)).toLocaleString()}`;
const fmtK = (v: number) => {
  const a = Math.abs(v);
  return a >= 1000 ? `$${Math.round(a / 1000)}K` : `$${Math.round(a)}`;
};

type Filter = "all" | RcpStatus;
const FILTER_KEYS: Filter[] = ["all", "pending", "processing", "approved"];
const FILTER_LABELS = ["All", "Pending", "Processing", "Approved"];

const FILTER_FN: Record<Filter, (r: Receipt) => boolean> = {
  all: () => true,
  pending: (r) => r.status === "pending",
  processing: (r) => r.status === "processing",
  approved: (r) => r.status === "approved",
};

type SortKey = "supplier" | "total" | "clsSort" | "statusSort" | "date";

const ArrowSvg = () => (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <line x1="5" y1="12" x2="19" y2="12" />
    <polyline points="12 5 19 12 12 19" />
  </svg>
);

const COLS: Array<{ k: SortKey; l: string }> = [
  { k: "supplier", l: "Supplier" },
  { k: "total", l: "Amount" },
  { k: "clsSort", l: "Classification" },
  { k: "statusSort", l: "Status" },
  { k: "date", l: "Date" },
];

export default function ReceiptsPage() {
  const [filterIdx, setFilterIdx] = useState(0);
  const filter: Filter = FILTER_KEYS[filterIdx];

  const [sortKey, setSortKey] = useState<SortKey>("date");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [rowActionSent, setRowActionSent] = useState<number | null>(null);
  const [panelBridgeSent, setPanelBridgeSent] = useState(false);

  const visible = useMemo(() => {
    const fn = FILTER_FN[filter];
    const arr = RECEIPTS.filter(fn).slice();
    arr.sort((a, b) => {
      if (sortKey === "supplier" || sortKey === "date") {
        return String(a[sortKey]).localeCompare(String(b[sortKey])) * sortDir;
      }
      return (((a[sortKey] as unknown as number) || 0) - ((b[sortKey] as unknown as number) || 0)) * sortDir;
    });
    return arr;
  }, [filter, sortKey, sortDir]);

  const totalCaptured = useMemo(() => RECEIPTS.reduce((a, r) => a + r.total, 0), []);

  const selected: Receipt | null = selectedIdx != null ? RECEIPTS[selectedIdx] : null;

  const onSelect = (i: number) => {
    setSelectedIdx((cur) => (cur === i ? null : i));
    setPanelBridgeSent(false);
  };
  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(1);
    }
  };
  const { openBridge } = useBridge();
  /** Per execution map §09 Receipts: every row action routes to capture-receipt
   *  (Vision → landed-cost build is the only write surface for this page). */
  const sendRowAction = (i: number) => {
    setRowActionSent(i);
    openBridge("ops", "capture-receipt");
    setTimeout(() => setRowActionSent(null), 1400);
  };
  const sendPanelBridge = () => {
    setPanelBridgeSent(true);
    openBridge("ops", "capture-receipt");
    setTimeout(() => setPanelBridgeSent(false), 1700);
  };

  // Detail panel computation
  const present = selected
    ? selected.comps.map((v, i) => ({ v, i })).filter((c) => c.v !== 0)
    : [];
  const absTotal = present.reduce((a, c) => a + Math.abs(c.v), 0) || 1;

  const routeHtml = (() => {
    if (!selected) return "";
    if (selected.cls === "delivery") {
      return `<strong>Delivery</strong> — attaches to inbound shipment ${selected.po}, not a loose expense. Adds ${fmtK(selected.comps[1])} freight to that PO&rsquo;s landed cost.`;
    }
    if (selected.cls === "expense") {
      return `<strong>Operating expense</strong> (${selected.expenseNote || "general"}) — routes to Finance, not into product cost.`;
    }
    return `<strong>Inventory</strong> — matched to ${selected.po}. Components assemble into per-unit landed cost.`;
  })();

  return (
    <div className="ops-receipts-page">
      <DeptHeader
        dept="ops"
        title="Receipts"
        meta={<><span className="live">Live</span> · Is every cost captured, classified, and feeding true product cost — automatically</>}
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="ops" page="capture-receipt">+ Add receipt</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={FILTER_LABELS} activeIndex={filterIdx} onChange={setFilterIdx} />

      {/* ───── KPIs ───── */}
      <div className="rcp-kpis">
        <div className="rcp-kpi">
          <div className="lbl">This month</div>
          <div className="val">{fmtK(214000)}</div>
          <div className="sub">28 receipts captured</div>
        </div>
        <div className="rcp-kpi">
          <div className="lbl">Product costs updated</div>
          <div className="val ai">19</div>
          <div className="sub">pushed to landed cost → CM1</div>
        </div>
        <div className="rcp-kpi">
          <div className="lbl">Pending review</div>
          <div className="val amber">
            {RECEIPTS.filter((r) => r.status === "pending" || r.status === "processing").length}
          </div>
          <div className="sub">need classification or approval</div>
        </div>
        <div className="rcp-kpi">
          <div className="lbl">Captured by Vision</div>
          <div className="val ai">82%</div>
          <div className="sub">photo → components, auto-tagged</div>
        </div>
      </div>

      {/* ───── AI strip ───── */}
      <AIStrip label={receiptsAI.label} meta={receiptsAI.meta} cards={receiptsAI.cards} />

      {/* ───── Receipts ledger + slide-in ───── */}
      <div className="rcp-section-label">
        Receipts
        <span className="count">
          {visible.length} this view · {fmtK(totalCaptured)} captured
        </span>
      </div>

      <div className={`led-split${selected ? " open" : ""}`}>
        <div className="led-main">
          <div className="rcp-ledger">
            <div className="rcp-head">
              {COLS.map((c) => {
                const active = sortKey === c.k;
                return (
                  <div
                    key={c.k}
                    className={`th${active ? " active" : ""}`}
                    onClick={() => handleSort(c.k)}
                  >
                    {c.l}
                    <span className="ar">{active ? (sortDir > 0 ? "▲" : "▼") : "▲"}</span>
                  </div>
                );
              })}
            </div>

            {visible.length === 0 ? (
              <div className="rcp-empty">No receipts in this view</div>
            ) : (
              visible.map((r) => {
                const act = actionForReceipt(r);
                return (
                  <div
                    key={r.idx}
                    className={`rcp-row${selectedIdx === r.idx ? " sel" : ""}`}
                    onClick={() => onSelect(r.idx)}
                  >
                    <span>
                      <span className="rr-sup">{r.supplier}</span>
                      <span className="rr-when">{r.when}</span>
                    </span>
                    <span className="rr-amt">
                      {fmtK(r.total)}<span className="u">total</span>
                    </span>
                    <span>
                      <span className={`cls-tag ${r.cls}`}>{CLASS_LABEL[r.cls]}</span>
                    </span>
                    <span>
                      <span className={`rcp-pill ${r.status}`}>
                        {r.status.charAt(0).toUpperCase() + r.status.slice(1)}
                      </span>
                    </span>
                    <span className="rcp-date">{r.date}</span>
                    <button
                      className={`rcp-act${act.kind === "view" ? " view" : ""}${rowActionSent === r.idx ? " sent" : ""}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        sendRowAction(r.idx);
                      }}
                    >
                      {rowActionSent === r.idx ? (
                        `${act.label} ✓`
                      ) : (
                        <>
                          {act.label}
                          <ArrowSvg />
                        </>
                      )}
                    </button>
                  </div>
                );
              })
            )}
          </div>
        </div>

        {/* ───── Vision extraction panel ───── */}
        <aside className="led-detail">
          <div className="led-detail-in">
            {!selected ? (
              <div className="xd-empty">
                <div className="ttl">Receipt extraction</div>
                <div className="lead">
                  Click a receipt to see the cost components Vision pulled out — base, freight, duty, handling — how it&rsquo;s classified, and the landed cost it updates downstream.
                </div>
              </div>
            ) : (
              <>
                <div className="xd-head">
                  <div>
                    <div className="xd-sup">{selected.supplier}</div>
                    <div className="xd-meta">
                      {selected.date} · {selected.po ?? "no PO"}
                      {selected.units > 0 ? ` · ${selected.units} units` : ""}
                    </div>
                  </div>
                  <button className="xd-clear" onClick={() => setSelectedIdx(null)}>
                    clear ✕
                  </button>
                </div>

                {selected.vision && (
                  <div className="xd-vision">
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
                      <circle cx="12" cy="12" r="3" />
                      <path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7z" />
                    </svg>
                    <div className="vt">
                      <b>Extracted by Vision</b> from the receipt photo — components read and tagged, not a lump total.
                    </div>
                  </div>
                )}

                <div className="xd-section">Cost components</div>
                {present.map(({ v, i }) => (
                  <div key={i} className="xd-comp">
                    <span className="cdot" style={{ background: COMP_COLOR[i] }} />
                    <span className="cn">
                      {COMP_LABEL[i]}
                      <span className="ctag">{i === 0 ? "supplier" : "landed add"}</span>
                    </span>
                    <span className="cv">
                      {v < 0 ? "−" : ""}{fmtUSD(v)}
                    </span>
                  </div>
                ))}
                <div className="xd-bar">
                  {present.map(({ v, i }) => (
                    <span
                      key={i}
                      style={{
                        width: `${((Math.abs(v) / absTotal) * 100).toFixed(1)}%`,
                        background: COMP_COLOR[i],
                      }}
                    />
                  ))}
                </div>

                <div className="xd-total">
                  <span className="l">Receipt total</span>
                  <span className="v">{fmtUSD(selected.total)}</span>
                </div>

                <div className="xd-route">
                  <div className="rl">Classification</div>
                  <div className="rb" dangerouslySetInnerHTML={{ __html: routeHtml }} />
                </div>

                {selected.cls === "inventory" && selected.product && selected.perUnit != null && (
                  <div className="xd-updates">
                    <div className="ul">What this updates</div>
                    <div className="xd-flow">
                      <span className="node">Receipt</span>
                      <span className="arr">→</span>
                      <span className="node">{selected.product}</span>
                      <span className="arr">→</span>
                      <span className="node">Landed {fmtUSD(selected.perUnit)}/u</span>
                      <span className="arr">→</span>
                      <span className="node cm">CM1</span>
                    </div>
                    <div className="un">
                      Per-unit landed becomes <strong>{fmtUSD(selected.perUnit)}</strong> across {selected.units} units — pushed into the Inventory Ledger and CM1 automatically on approval.
                    </div>
                  </div>
                )}
                {selected.cls === "delivery" && (
                  <div className="xd-updates">
                    <div className="ul">What this updates</div>
                    <div className="xd-flow">
                      <span className="node">Delivery {fmtK(selected.comps[1])}</span>
                      <span className="arr">→</span>
                      <span className="node">{selected.po} freight</span>
                      <span className="arr">→</span>
                      <span className="node cm">Landed cost</span>
                    </div>
                    <div className="un">
                      Folds into the shipment&rsquo;s landed cost instead of floating as a loose operating line.
                    </div>
                  </div>
                )}

                {(() => {
                  const act = actionForReceipt(selected);
                  const label = ACTION_LABEL_PANEL[act.kind];
                  return (
                    <>
                      <button
                        className={`xd-bridge${panelBridgeSent ? " sent" : ""}`}
                        onClick={sendPanelBridge}
                      >
                        {panelBridgeSent ? label.replace("→ Bridge", "sent ✓").replace("Bridge", "sent ✓") : label}
                      </button>
                      {selected.status !== "approved" && (
                        <button className="xd-bridge secondary" onClick={() => setSelectedIdx(null)}>
                          Reclassify
                        </button>
                      )}
                    </>
                  );
                })()}
              </>
            )}
          </div>
        </aside>
      </div>
    </div>
  );
}
